import yaml
import json
from pathlib import Path
from dataclasses import dataclass, field
from typing import Optional

@dataclass
class RadarEntry:
    id: str
    title: str
    ring: str
    quadrant: str
    rationale: str
    adr_refs: list = field(default_factory=list)
    deprecated: bool = False

def load_radar(path: Path) -> dict[str, RadarEntry]:
    raw = yaml.safe_load(path.read_text())
    return {
        e["id"]: RadarEntry(**{k: e.get(k, [] if k == "adr_refs" else False if k == "deprecated" else "") for k in RadarEntry.__dataclass_fields__})
        for e in raw.get("entries", [])
    }

def diff_radars(old_path: Path, new_path: Path) -> list[dict]:
    old = load_radar(old_path)
    new = load_radar(new_path)
    changes = []

    all_ids = set(old) | set(new)
    for entry_id in sorted(all_ids):
        o = old.get(entry_id)
        n = new.get(entry_id)

        if o is None and n is not None:
            changes.append({"change": "added", "id": entry_id, "ring": n.ring, "quadrant": n.quadrant})
        elif o is not None and n is None:
            changes.append({"change": "removed", "id": entry_id, "prev_ring": o.ring})
        elif o is not None and n is not None:
            if o.ring != n.ring:
                changes.append({"change": "ring_change", "id": entry_id,
                                 "from_ring": o.ring, "to_ring": n.ring,
                                 "adr_refs": n.adr_refs})
            if o.deprecated != n.deprecated:
                changes.append({"change": "deprecated" if n.deprecated else "reactivated",
                                 "id": entry_id})
    return changes

def generate_changelog(old_path: Path, new_path: Path) -> str:
    diffs = diff_radars(old_path, new_path)
    if not diffs:
        return "No changes detected between radar versions."

    lines = ["## Radar Changelog", ""]
    for d in diffs:
        c = d["change"]
        if c == "added":
            lines.append(f"- **ADDED** `{d['id']}` → ring: {d['ring']}, quadrant: {d['quadrant']}")
        elif c == "removed":
            lines.append(f"- **REMOVED** `{d['id']}` (was: {d['prev_ring']})")
        elif c == "ring_change":
            adrs = ", ".join(d.get("adr_refs", [])) or "none"
            lines.append(f"- **RING CHANGE** `{d['id']}`: {d['from_ring']} → {d['to_ring']} (ADRs: {adrs})")
        elif c == "deprecated":
            lines.append(f"- **DEPRECATED** `{d['id']}`")
        elif c == "reactivated":
            lines.append(f"- **REACTIVATED** `{d['id']}`")
    return "\n".join(lines)

if __name__ == "__main__":
    import sys
    if len(sys.argv) != 3:
        print("Usage: radar_diff.py <old_radar.yaml> <new_radar.yaml>")
        sys.exit(1)
    print(generate_changelog(Path(sys.argv[1]), Path(sys.argv[2])))
